import { List, Map } from 'immutable'
import { PSPDFKitError, error, info, invariant } from '@pspdfkit/shared'

import {
  deserializeAnnotation,
  deserializeFormFieldValue,
  serializeAnnotation,
  serializeFormFieldValue,
} from '../serializers/utils'
import {
  fromJSON as deserializeBookmark,
  toJSON as serializeBookmark,
} from '../serializers/BookmarkSerializer'
import { RESTProviderState } from './RESTProviderState'
import { getFormFieldValueID } from '@/models/form-fields/FormFieldValue'
import { CREATE_REASON_LOAD } from '../Provider'
import { getVersionHeader } from '@/utils/environment'

import type { Annotation, Attachment, Bookmark, FormFieldValue } from '@/models'
import type { ReadStateProvider, ReadStateProviderCallbacks } from '../ReadStateProvider'
import type { AnnotationProvider, AnnotationProviderCallbacks } from '../AnnotationProvider'
import type { BookmarkProvider, BookmarkProviderCallbacks } from '../BookmarkProvider'
import type { FormFieldValueCallbacks, FormFieldValueProvider } from '../FormFieldValueProvider'
import type { ID as BookmarkID } from '@/models/Bookmark'
import type { IObject } from '@/typings/utils'

/**
 * A REST interface to annotation loading. It can't handle real time update and will fetch
 * annotations per-page.
 *
 * @todo How do we handle errors?
 */
export class RESTProvider
  implements ReadStateProvider, AnnotationProvider, BookmarkProvider, FormFieldValueProvider
{
  _readStateCallbacks: ReadStateProviderCallbacks | null | undefined
  _setReadStateCallbacksPromiseResolve: (() => void) | null
  _setReadStateCallbacksPromise: Promise<void>
  annotationCallbacks: AnnotationProviderCallbacks | null | undefined
  bookmarkCallbacks: BookmarkProviderCallbacks | null | undefined
  formFieldValueCallbacks: FormFieldValueCallbacks | null | undefined
  state: RESTProviderState
  canCreateBackendOrphanWidgets = true

  constructor(
    serverURL: string,
    authPayload: {
      token: string
    },
    {
      isFormsEnabled,
    }: {
      isFormsEnabled: boolean
    },
  ) {
    this.state = new RESTProviderState({
      serverURL,
      authPayload,
      isFormsEnabled,
    })

    this._setReadStateCallbacksPromise = new Promise(resolve => {
      this._setReadStateCallbacksPromiseResolve = resolve
    })
  }

  /*************************
   * Connection management *
   *************************/
  async load(): Promise<RESTProvider> {
    this.state = this.state.set('isLoaded', true)

    if (this.state.isFormsEnabled) {
      // Form Field Values are not loaded on a per-page basis. Thus, we fetch them all in here
      await this._initializeFormFieldValues()
    }

    return this
  }

  destroy(): void {}

  setReadStateCallbacks(readStateCallbacks: ReadStateProviderCallbacks) {
    this._readStateCallbacks = readStateCallbacks

    this._setReadStateCallbacksPromiseResolve?.()
  }

  setAnnotationCallbacks(annotationCallbacks: AnnotationProviderCallbacks) {
    this.annotationCallbacks = annotationCallbacks
  }

  setBookmarkCallbacks(bookmarkCallbacks: BookmarkProviderCallbacks) {
    this.bookmarkCallbacks = bookmarkCallbacks
  }

  setFormFieldValueCallbacks(formFieldValueCallbacks: FormFieldValueCallbacks) {
    this.formFieldValueCallbacks = formFieldValueCallbacks
  }

  /******************
   * Annotation API *
   ******************/
  async createAnnotation(
    annotation: Annotation,
    attachments: Map<string, Attachment>,
  ): Promise<void> {
    this._verifyLoaded()

    // We delete id from content so the server doesn't persist the ID in the content.
    const { id, ...content } = serializeAnnotation(annotation)
    const annotationBody = {
      id,
      content,
    }

    const response = await this._request('/annotations', 'POST', annotationBody)

    if (response.status !== 200) {
      throw new PSPDFKitError(
        'PSPDFKit Document Engine returned an error, when saving an annotation.',
      )
    }

    const json = await response.json()

    if (json.error === 'attachment_missing') {
      // When the attachment is not already stored on the server, we need to attach the
      // attachments to the request
      const newBody = createFormData(annotationBody, attachments)

      const attachmentResponse = await this._request('/annotations', 'POST', newBody)

      if (attachmentResponse.status !== 200) {
        throw new PSPDFKitError(
          'PSPDFKit Document Engine returned an error, when saving an annotation attachment.',
        )
      }
    }
  }

  async updateAnnotation(annotation: Annotation): Promise<void> {
    this._verifyLoaded()

    // We delete id from content so the server doesn't persist the ID in the content.
    const { id, ...content } = serializeAnnotation(annotation)

    await this._request(`/annotations/${id}`, 'PUT', {
      id,
      content,
    })
  }

  async deleteAnnotation(annotation: Annotation): Promise<void> {
    this._verifyLoaded()

    await this._request(`/annotations/${annotation.id}`, 'DELETE')
  }

  /******************
   * Bookmark API *
   ******************/
  async createBookmark(bookmark: Bookmark): Promise<void> {
    this._verifyLoaded()

    // Make sure bookmarks are loaded.
    await this.loadBookmarks()

    // We delete id from content so the server doesn't persist the ID in the content.
    const { id, ...content } = serializeBookmark(bookmark)
    const response = await this._request('/bookmarks', 'POST', {
      id,
      content,
    })

    if (response.status !== 200) {
      throw new PSPDFKitError(
        'PSPDFKit Document Engine returned an error, when saving an bookmark.',
      )
    }
  }

  async updateBookmark(bookmark: Bookmark): Promise<void> {
    this._verifyLoaded()

    // Make sure bookmarks are loaded.
    await this.loadBookmarks()

    // We delete id from content so the server doesn't persist the ID in the content.
    const { id, ...content } = serializeBookmark(bookmark)

    await this._request(`/bookmarks/${id}`, 'PUT', {
      id,
      content,
    })
  }

  async deleteBookmark(bookmarkId: BookmarkID): Promise<void> {
    this._verifyLoaded()

    // Make sure bookmarks are loaded.
    await this.loadBookmarks()
    await this._request(`/bookmarks/${bookmarkId}`, 'DELETE')
  }

  /******************
   * FormFieldValue API *
   ******************/
  async setFormFieldValue(formFieldValue: FormFieldValue): Promise<void> {
    this._verifyLoaded()

    const payload = {
      id: getFormFieldValueID(formFieldValue),
      content: serializeFormFieldValue(formFieldValue),
    }

    await this._request('/form-field-values', 'POST', {
      formFieldValues: [payload],
    })
  }

  // Stub to be implemented when this provider is supported
  async createFormFieldValue(): Promise<void> {
    return
  }

  // Stub to be implemented when this provider is supported
  async deleteFormFieldValue(): Promise<void> {
    return
  }

  async loadAnnotationsForPageIndex(pageIndex: number): Promise<void> {
    this._verifyLoaded()

    if (this.state.alreadyLoadedPages.has(pageIndex)) {
      await this.state.alreadyLoadedPages.get(pageIndex)

      return
    }

    try {
      const payloadPromise = this._request(`/page-${pageIndex}-annotations`, 'GET')
        .then(response => response.json())
        .catch(error => {
          throw error
        })

      // We save the promise so that if `loadAnnotationsForPageIndex` is called again
      // before the promise resolves the new calls awaits for the promise as well!
      this.state = this.state.setIn(['alreadyLoadedPages', pageIndex], payloadPromise)

      const payload = await payloadPromise

      // At this point we don't need a reference to the original promise anymore.
      this.state = this.state.setIn(['alreadyLoadedPages', pageIndex], Promise.resolve())

      const additions = List().withMutations(mutableAdditions => {
        payload.annotations.forEach(record => {
          try {
            mutableAdditions.push(deserializeAnnotation(record.id, record.content))
          } catch (error) {
            info(
              `Skipped creating annotation #${record.id} from payload because an error occurred while deserializing.`,
              record.content,
            )
            info(error)
          }
        })
      })

      if (additions.size > 0) {
        invariant(this.annotationCallbacks)
        this.annotationCallbacks.createAnnotations(additions, Map(), CREATE_REASON_LOAD)
      }
    } catch (error) {
      this._handleError(error, 'annotations')
    }
  }

  async loadBookmarks() {
    this._verifyLoaded()

    if (this.state.loadBookmarksPromise) {
      await this.state.loadBookmarksPromise

      return
    }

    try {
      const payloadPromise = this._request('/bookmarks', 'GET')
        .then(response => response.json())
        .then(payload => payload.data)
        .catch(error => {
          throw error
        })

      // We save the promise so that if `loadBookmarks` is called again
      // before the promise resolves the new calls awaits for the promise as well!
      this.state = this.state.set('loadBookmarksPromise', payloadPromise)

      const payload = await payloadPromise

      // At this point we don't need a reference to the original promise anymore.
      this.state = this.state.set('loadBookmarksPromise', Promise.resolve())
      invariant(Array.isArray(payload.bookmarks), 'Unexpected reply from bookmarks endpoint.')

      const bookmarks = List().withMutations(mutableBookmarks => {
        payload.bookmarks.forEach((json: Record<string, any>) => {
          try {
            mutableBookmarks.push(deserializeBookmark(json.id, json.content))
          } catch (error) {
            info(
              `Skipped creating bookmark #${json.id} from payload because an error occurred while deserializing.`,
              // @ts-expect-error
              json,
            )
            info(error)
          }
        })
      })

      if (bookmarks.size > 0) {
        invariant(this.bookmarkCallbacks)
        this.bookmarkCallbacks.createBookmarks(bookmarks, CREATE_REASON_LOAD)
      }
    } catch (error) {
      this._handleError(error, 'bookmarks')
    }
  }

  async syncChanges(): Promise<void> {}

  async _initializeFormFieldValues(): Promise<void> {
    const request = await this._request('/form-field-values', 'GET')
    const response = await request.json()

    invariant(
      Array.isArray(response.formFieldValues),
      'Unexpected reply from form-values endpoint.',
    )

    const formFieldValues = List<FormFieldValue>(
      response.formFieldValues
        .map(({ content: formFieldValueJSON }) => {
          try {
            return deserializeFormFieldValue(formFieldValueJSON)
          } catch (error) {
            info(
              `Skipped form field value ${formFieldValueJSON.name} from payload because an error occurred while deserializing.`,
              formFieldValueJSON,
            )
            info(error)

            return null
          }
        })
        .filter(Boolean),
    )

    invariant(this.formFieldValueCallbacks)

    if (this.state.ignoredFormFieldNames && this.state.ignoredFormFieldNames.size) {
      this.formFieldValueCallbacks.setFormFieldValues(
        formFieldValues.filter(value => !this.state.ignoredFormFieldNames?.includes(value.name)),
      )
    } else {
      this.formFieldValueCallbacks.setFormFieldValues(formFieldValues)
    }
  }

  _handleError(e: Error, type: 'annotations' | 'bookmarks') {
    error(`Loading or updating ${type} failed:

${e.message}`)
  }

  _request(
    path: string,
    method: 'GET' | 'POST' | 'PUT' | 'DELETE',
    body?: IObject,
  ): Promise<IObject> {
    invariant(this.state.authPayload != null, 'Cannot call request without authPayload')

    const contentTypeHeader =
      !(body instanceof FormData) && typeof body === 'object'
        ? {
            'Content-Type': 'application/json',
          }
        : null
    const headers = {
      'X-PSPDFKit-Token': this.state.authPayload.token,
      'PSPDFKit-Platform': 'web',
      'PSPDFKit-Version': getVersionHeader(),
      ...contentTypeHeader,
    }

    return fetch(`${this.state.serverURL}${path}`, {
      method,
      headers,
      body:
        body instanceof FormData
          ? body
          : typeof body === 'object'
          ? JSON.stringify(body)
          : undefined,
      credentials: 'include',
    })
  }

  _verifyLoaded() {
    if (!this.state.isLoaded) {
      throw new Error('not loaded')
    }
  }

  setDocumentHandleConflictCallback = () => {}

  setIgnoredFormFieldNames(formFields: List<string>) {
    this.state = this.state.set('ignoredFormFieldNames', formFields)
  }

  /**
   * Update tab order from the backend.
   */
  async updateTabOrder() {
    throw new PSPDFKitError('Tab order is not supported on this backend.')
  }

  async setTabOrder() {
    throw new PSPDFKitError('setTabOrder is not supported on this backend.')
  }
}

function createFormData(annotationBody, attachments) {
  const formData = new FormData()

  formData.append('annotation', JSON.stringify(annotationBody))
  attachments.forEach((attachment, attachmentId) => {
    if (attachmentId && attachment.data) {
      formData.append(attachmentId, attachment.data)
    }
  })

  return formData
}
