import { Map } from 'immutable'
import * as Immutable from 'immutable'

import type { List } from 'immutable'

interface IRESTProviderState {
  alreadyLoadedPages: Map<number, Promise<void>>
  serverURL: string | null
  authPayload: {
    token: string
  } | null
  isLoaded: boolean
  isFormsEnabled: boolean
  loadBookmarksPromise: Promise<void> | null | undefined
  ignoredFormFieldNames?: List<string> | null
}

export class RESTProviderState extends Immutable.Record<IRESTProviderState>({
  alreadyLoadedPages: Map(),
  serverURL: null,
  authPayload: null,
  isLoaded: false,
  isFormsEnabled: true,
  loadBookmarksPromise: null,
  ignoredFormFieldNames: null,
}) {
  /**
   * Used to remember which page annotations have already been loaded.
   *
   * @member {Immutable.Map.<number, Promise.<void>>} alreadyLoadedPages
   */
  override alreadyLoadedPages: Map<number, Promise<void>>

  /**
   * @member {string} serverURL
   */
  override serverURL: string

  /**
   * @member {object} authPayload
   */
  override authPayload: {
    token: string
  }
  override isLoaded: boolean
  override isFormsEnabled: boolean

  /**
   * Used to fire loadBookmarks only once.
   *
   * @member {?Promise.<void>} loadBookmarksPromise
   */
  override loadBookmarksPromise: Promise<void> | null | undefined

  /**
   * Used to know which form field values can be omitted safely.
   *
   * @member {?List.<string>} ignoredFormFieldNames
   */
  override ignoredFormFieldNames?: List<string>
}
